  ('promotion-d0d1b9a2-moex-00197', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-f6c431ec', 'sub-promotion-d0d1b9a2-03', NULL, 'single_choice', '社會救助法中所用的最低生活費是以下列何者為標準訂定之？', '["每人可支配所得中位數", "每人可支配所得平均數", "平均國民所得", "每人消費性支出中位數"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:04+00:00", "source_pdf_sha1": "9dcd589c3d00", "answer_pdf_sha1": "7631fcb9fa89", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00198', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-f6c431ec', 'sub-promotion-d0d1b9a2-03', NULL, 'single_choice', '下列何者的主要財務來源不是稅收？', '["老年農民福利津貼", "勞工老年年金", "長期照顧服務給付", "身心障礙者生活補助"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:04+00:00", "source_pdf_sha1": "9dcd589c3d00", "answer_pdf_sha1": "7631fcb9fa89", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00199', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-f6c431ec', 'sub-promotion-d0d1b9a2-03', NULL, 'single_choice', '依全民健康保險法現行規定，政府每年度負擔全民健康保險之總經費，不得少於每年度保險經費 扣除法定收入後金額的：', '["16%", "36%", "46%", "56%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:04+00:00", "source_pdf_sha1": "9dcd589c3d00", "answer_pdf_sha1": "7631fcb9fa89", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00200', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-f6c431ec', 'sub-promotion-d0d1b9a2-03', NULL, 'single_choice', '財產稅的新觀點（newview）是：', '["將財產稅視為對土地課稅，因為土地供給不變，故所有租稅由地主負擔", "將財產稅視為對資本課稅，在高稅率地區相對較不流動的生產要素會負擔較重的稅負", "將財產稅視為對地上建築物課稅，由於地上建築物的供給彈性無限大，地上建築物的需求者負 擔所有租稅", "將財產稅視為貨物稅，租稅負擔視地上建築物供給者與需求者的相對彈性而定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:04+00:00", "source_pdf_sha1": "9dcd589c3d00", "answer_pdf_sha1": "7631fcb9fa89", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00201', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-f6c431ec', 'sub-promotion-d0d1b9a2-03', NULL, 'single_choice', '由於資本利得係於實現年度一次課徵，納稅義務人可能就所累積多年的資本利得一次繳交大筆稅 額，因而不願賣出長期持有的資產，此一效果稱為：', '["閉鎖效果（lock-ineffect）", "排擠效果（crowding-outeffect）", "民主效果（democracyeffect）", "群聚效果（clusteringeffect）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:04+00:00", "source_pdf_sha1": "9dcd589c3d00", "answer_pdf_sha1": "7631fcb9fa89", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00202', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-f6c431ec', 'sub-promotion-d0d1b9a2-03', NULL, 'single_choice', '所謂稅式支出（taxexpenditure）係指：', '["以租稅作為經費來源的政府支出", "人民為繳納租稅所作的經費支出", "由於租稅減免規定所減少之稅收", "政府為課徵租稅所產生的經費支出 12060"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:04+00:00", "source_pdf_sha1": "9dcd589c3d00", "answer_pdf_sha1": "7631fcb9fa89", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "0901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL)
